{
  "claims": [
    {
      "claim_text": "苹果是一种非常常见的水果，口感清脆，味道酸甜，适合直接食用，也可以用于榨汁、烘焙、制作果酱和沙拉。",
      "citation_locator": "line:5",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果常被看作日常饮食中最基础的水果之一。",
      "citation_locator": "line:5",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果的特点包括：价格相对稳定，购买方便；口感清爽，适合作为加餐水果；含有膳食纤维、维生素和多种植物化合物；既可以生吃，也可以加工成多种食品。",
      "citation_locator": "line:9-12",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果并不是某一种营养素特别突出的水果，但它的优势在于营养比较均衡，适合长期、规律地加入日常饮食。",
      "citation_locator": "line:16",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果中含有一定量的膳食纤维，尤其是果皮部分。",
      "citation_locator": "line:20",
      "confidence_status": "cited"
    },
    {
      "claim_text": "膳食纤维有助于增加饱腹感，也有利于维持较好的肠道状态。",
      "citation_locator": "line:20",
      "confidence_status": "cited"
    },
    {
      "claim_text": "如果苹果清洗干净，可以连皮一起吃，这样能摄入更多膳食纤维。",
      "citation_locator": "line:22",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果中含有维生素 C、钾等营养成分。",
      "citation_locator": "line:26",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果的维生素 C 含量通常不如橙子、猕猴桃等水果高。",
      "citation_locator": "line:26",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果中还含有多酚类物质等植物化合物，这类成分通常与水果的颜色、风味和抗氧化特性有关。",
      "citation_locator": "line:30",
      "confidence_status": "cited"
    },
    {
      "claim_text": "不同品种的苹果在甜度、酸度、硬度和香气上有所区别。",
      "citation_locator": "line:34",
      "confidence_status": "cited"
    },
    {
      "claim_text": "红富士甜度较高，口感脆，汁水较多，适合直接食用。",
      "citation_locator": "line:38",
      "confidence_status": "cited"
    },
    {
      "claim_text": "嘎啦苹果个头适中，香味明显，口感偏甜，适合直接食用、沙拉。",
      "citation_locator": "line:39",
      "confidence_status": "cited"
    },
    {
      "claim_text": "青苹果酸味较明显，口感清爽，适合直接食用、榨汁、烘焙。",
      "citation_locator": "line:40",
      "confidence_status": "cited"
    },
    {
      "claim_text": "蛇果外观颜色深红，口感较甜，适合直接食用、摆盘。",
      "citation_locator": "line:41",
      "confidence_status": "cited"
    },
    {
      "claim_text": "黄元帅香气明显，口感较软，适合直接食用、制作甜点。",
      "citation_locator": "line:42",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果适合作为早餐搭配、下午加餐或饭后水果。",
      "citation_locator": "line:46",
      "confidence_status": "cited"
    },
    {
      "claim_text": "对于大多数人来说，每天吃一个中等大小的苹果是比较常见的选择。",
      "citation_locator": "line:46",
      "confidence_status": "cited"
    },
    {
      "claim_text": "推荐的吃法包括：直接清洗后食用；切块加入酸奶或燕麦中；与胡萝卜、橙子等一起榨汁；切片后用于烘焙；与坚果搭配作为加餐。",
      "citation_locator": "line:50-54",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果虽然健康，但也不应该完全替代正餐。合理饮食应该包括主食、蛋白质、蔬菜、水果和适量脂肪。",
      "citation_locator": "line:56",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果相对耐保存，但不同环境下保存时间差异较大。",
      "citation_locator": "line:60",
      "confidence_status": "cited"
    },
    {
      "claim_text": "短时间内食用，可以将苹果放在阴凉、通风处保存，避免阳光直射和高温。",
      "citation_locator": "line:64",
      "confidence_status": "cited"
    },
    {
      "claim_text": "一次购买较多时，可以将苹果放入冰箱冷藏室以延长保存时间并保持口感。",
      "citation_locator": "line:68",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果会释放乙烯，可能加快一些水果成熟，建议避免与香蕉、猕猴桃等长时间密封放在一起。",
      "citation_locator": "line:72",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果适合大多数人群食用，包括学生、上班族和老年人，方便携带，适合作为日常健康零食。",
      "citation_locator": "line:76",
      "confidence_status": "cited"
    },
    {
      "claim_text": "需要注意：胃肠敏感的人空腹吃苹果可能不适；血糖控制要求高的人应注意总水果摄入量；牙齿敏感的人吃偏酸苹果后可漱口；婴幼儿应切小块或做成果泥避免噎食。",
      "citation_locator": "line:80-83",
      "confidence_status": "cited"
    },
    {
      "claim_text": "苹果是一种适合长期食用的日常水果，其优势在于购买方便、口感稳定、吃法多样、适合多数人群。",
      "citation_locator": "line:87",
      "confidence_status": "cited"
    }
  ],
  "concept": {
    "title": "苹果：营养均衡的日常水果",
    "aliases": ["苹果"]
  },
  "entity": null,
